class Trader:
 L=10;Q=20
 def run(self,state:TradingState):
  res:Dict[str,List[Order]]={}
  try:data=json.loads(state.traderData) if state.traderData else {}
  except Exception:data={}
  hist=data.get('c',[])
  mids={}
  for p,d in state.order_depths.items():
   if d.buy_orders and d.sell_orders:mids[p]=(max(d.buy_orders)+min(d.sell_orders))/2
  if 'MICROCHIP_CIRCLE' in mids:
   hist.append(mids['MICROCHIP_CIRCLE']);hist=hist[-110:]
  for p,d in state.order_depths.items():
   if p not in MODE or not d.buy_orders or not d.sell_orders:
    res[p]=[];continue
   if MODE[p]=='static':
    fair=M[p];take=Z[p]*S[p];edge=EDGE[p]
   else:
    fair=mids[p];take=10**9;edge=EDGE[p]
    if p=='MICROCHIP_OVAL' and len(hist)>50:
     fair+=1.25*0.067*(hist[-1]-hist[-51]);take=5.5
    elif p=='MICROCHIP_SQUARE' and len(hist)>100:
     fair+=0.75*0.138*(hist[-1]-hist[-101]);take=6.0
   res[p]=self.tr(p,d,int(state.position.get(p,0)),fair,take,edge,IMP[p])
  return res,0,json.dumps({'c':hist},separators=(',',':'))
 def tr(self,p,d,pos,fair,take,edge,imp):
  bb=max(d.buy_orders);ba=min(d.sell_orders);bc=max(0,self.L-pos);sc=max(0,self.L+pos);out=[]
  if bc>0 and ba<=fair-take:
   q=min(bc,self.Q,-int(d.sell_orders[ba]))
   if q>0:out.append(Order(p,ba,q));bc-=q
  if sc>0 and bb>=fair+take:
   q=min(sc,self.Q,int(d.buy_orders[bb]))
   if q>0:out.append(Order(p,bb,-q));sc-=q
  if ba-bb>2*imp:bid,ask=bb+imp,ba-imp
  elif ba-bb>1:bid,ask=bb+1,ba-1
  else:bid,ask=bb,ba
  if bc>0 and bid<=fair-edge:out.append(Order(p,bid,min(self.Q,bc)))
  if sc>0 and ask>=fair+edge:out.append(Order(p,ask,-min(self.Q,sc)))
  return out
